// 初始化新项目
cjpm init my_project

// 编译项目
cjpm build

// 添加依赖
cjpm add github.com/example/lib

// 启动调试会话
cjdb run main.cj

// 设置断点
break main:15

// 查看变量值
print variable_name

// 格式化单个文件
cjfmt src/main.cj

// 格式化整个目录
cjfmt src/

// 启动语言服务器（通常由IDE集成）
LSPServer --port 8080

// 客户端连接示例（伪代码）
// IDE通过LSP协议与服务器通信，发送textDocument/didOpen等通知

// 反序列化CHIR文件
chir_dis output.chir

// 输出反序列化结果到文本文件
chir_dis output.chir -o output.txt

// 初始化项目
cjpm init

// 安装依赖
cjpm install

// 构建项目
cjpm build

// 启动调试会话
cjdb run main.cj

// 设置断点
break main:10

// 继续执行
continue

// 格式化单个文件
cjfmt src/main.cj

// 格式化整个目录
cjfmt src/

// 检查单个文件
cjlint src/main.cj

// 检查整个项目
cjlint .

// 运行测试并收集覆盖率
cjcov run tests/

// 生成 HTML 报告
cjcov report --format html

// 启动语言服务器
cangjie-lsp start

// 配置编辑器以连接到服务器

// 启动性能分析
cjprof record ./myapp

// 生成分析报告
cjprof report

// 源代码断点
breakpoint set --file test.cj --line 4
b test.cj:4

// 函数断点
breakpoint set --name test
b test

// 条件断点
breakpoint set --file test.cj --line 4 --condition a==12

// 配置捕获 SIGSEGV
(cjdb) process handle -p true -s true -n true SIGSEGV
